    "deployment_ready": false,
    "rollback_capable": true,
    "rollback_plan": "Redeploy previous container image. Straightforward and low-risk since this is a new service. Verify rollback doesn't leave users in an inconsistent 'pending KYC' state if a provisional mode is added later.",
    "monitoring_coverage": "Baseline metrics exist (kyc_checks_total, kyc_duration_histogram, /health). Missing: alerting on Onfido error rate spike, alerting on registration failure rate, and the ability to distinguish provider outage from legitimate verification failures.",
    "on_call_documentation": "Not mentioned. On-call runbook needed covering: (1) How to identify Onfido outage vs. service issue, (2) What to do when Onfido is down (currently: nothing, users just fail), (3) How to manually verify/approve users if needed for regulatory compliance during extended outage.",
    "new_infrastructure_required": {
      "new_env_vars": [],
      "new_services": [
        "Async retry queue (e.g., SQS, RabbitMQ) if implementing deferred KYC verification path"
      ],
      "new_queues_topics": [
        "KYC retry/deferred verification queue if async path is adopted"
      ],
      "config_changes": [
        "Circuit breaker configuration: error threshold, window size, open duration, half-open probe count"
      ],
      "infra_provisioning": []
    },
    "database_safety": {
      "has_migrations": false,
      "reversible": false,
      "data_preserving": false,
      "large_table_impact": false,
      "details": "No database migration details provided for review."
    },
    "verdict": "NOT READY"
  },

  "escalations": [
    {
      "type": "infrastructure_gap",
      "issue": "No circuit breaker on external dependency with lower SLA than internal target",
      "reason": "Onfido's 99.9% SLA is below the team's 99.95% target. Without a circuit breaker or degraded mode, Onfido downtime guarantees an SLA breach and risks cascading failure (thread pool exhaustion) that takes down the entire service, not just KYC. This is a mathematical certainty, not a theoretical risk.",
      "routed_to": "Coach K"
